var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"당신이 전송한 영상을 확인해 봤어요, 나이트.","JPN":"あなたが送ってくれた映像を確認しました、ナイト。","ENG":"I saw the video you sent over, Knight.","TWN":"我看到妳傳送過來的影像了，騎士。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"아주 흥미롭더군요.","JPN":"実に興味深い……","ENG":"It was very interesting...","TWN":"非常有意思。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"알트 소대라고 했던가요?","JPN":"アルト小隊、でしたっけ？","ENG":"The ALT Squad, was it?","TWN":"妳是說阿爾特小隊嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"네. 그 이름으로 활동하기 시작한 시점과 얼터너티브 실험체들이 행방을 감춘 시기도 일치합니다.","JPN":"はい。その名で活動を開始した時期と、オルタナティブ実験体が行方をくらました時期も一致しています。","ENG":"Yes, your Excellency. She started working with them right when the Alternative Type test subjects went into hiding.","TWN":"是的，以這個名字開始進行活動的時間，和實驗體們銷聲匿跡的時間是一致的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"훌륭하군요.","JPN":"素晴らしい。","ENG":"Excellent.","TWN":"真是太好了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"이젠 찾을 수 없을 거라고 생각했는데, 이렇게 건강한 모습으로 나타나 주다니요.","JPN":"もう見つからないと思っていたのに、このように元気な姿で現れてくれるなんて。","ENG":"I thought we lost her forever... Who knew she would pop up looking completely fine?","TWN":"我還以為再也找不到他們了，沒想到現在卻這麼有精神地出現我面前。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"큰 공로를 세웠어요, 나이트. 이제야 모든 일이 순리대로 돌아가네요.","JPN":"大きな功績を立ててくれました、ナイト。やっと全てが正しい軌道に戻りますね。","ENG":"Fantastic work, Knight. Everything is finally going as planned.","TWN":"妳立了大功，騎士。這樣一切都順利起來了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"선택 받은 순례자들이 약속의 땅으로 들어가기 위해서는 그들이 반드시 필요해요.","JPN":"選ばれし巡礼者たちが約束の地に入るためには、必ず彼らが必要です。","ENG":"We need them in order for the chosen pilgrims to return to the promised land.","TWN":"被選中的巡禮者們要進入應許之地，他們是不可或缺的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"당신의 능력을 믿고 기다리겠어요.","JPN":"あなたの能力を信じて待つとしましょう。","ENG":"I trust you'll handle the rest.","TWN":"我相信妳的能力，等妳的好消息。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"감사합니다! 퀸!","JPN":"ありがとうございます！　クイーン！","ENG":"Thank you! My Queen!","TWN":"謝謝您，女王陛下！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"반드시 실험체들을 확보해 보이겠습니다!","JPN":"必ず、実験体を確保してみせます！","ENG":"I'll secure the test subjects, no matter what!","TWN":"我一定會確保實驗體的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>후우.......</color>","JPN":"<color=#ffd34c>ふう……</color>","ENG":"<color=#ffd34c>*Sigh*</color>","TWN":"<color=#ffd34c> 呼……</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>각 부대에 전달한다!</color>","JPN":"<color=#ffd34c>各部隊への伝達事項だ！</color>","ENG":"<color=#ffd34c>Send a message to all the troops!</color>","TWN":"<color=#ffd34c> 傳令給各部隊！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>작전 방침을 변경하겠다.</color>","JPN":"<color=#ffd34c>作戦方針を変更する。</color>","ENG":"<color=#ffd34c>I'm making changes to the operation.</color>","TWN":"<color=#ffd34c>改變作戰方針。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>실험체 관리 인력을 제외한 전 병력은 추적 부대로 재편성한다.</color>","JPN":"<color=#ffd34c>実験体の管理メンバーを除き、全兵力を追跡部隊に再編成する。</color>","ENG":"<color=#ffd34c>All troops except those managing the test subjects will be reassigned to the manhunt.</color>","TWN":"<color=#ffd34c>除了實驗體管理人員以外，其餘兵力重新整編為追蹤部隊。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>편성이 끝나는 대로 해당 목표를 추적, 생포해 올 것.</color>","JPN":"<color=#ffd34c>編成が終わり次第、決まった目標を追跡し、生け捕りにすること。</color>","ENG":"<color=#ffd34c>As soon as the units have been reorganized, track down and capture the target alive.</color>","TWN":"<color=#ffd34c>編隊結束後，立刻追蹤並俘虜相關目標。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>......팔다리 하나쯤 날아가 버려도 상관없다!</color>","JPN":"<color=#ffd34c>……手足一本くらい吹っ飛んでしまっても構わない！</color>","ENG":"<color=#ffd34c>Don't worry about bringing the target back in one piece!</color>","TWN":"<color=#ffd34c>……就算打斷她的手腳也無所謂！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>숨만 붙여서 끌고 오도록! 이상!</color>","JPN":"<color=#ffd34c>息さえしてればいいから連れてくるんだ！　以上！</color>","ENG":"<color=#ffd34c>Just make sure she's still breathing! Over!</color>","TWN":"<color=#ffd34c>只要留有一口氣就行了！完畢！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};